insert into public.ingredient_help (key, title, what, where_to_find, best_options, tips, substitutes, allergy_warnings, why_it_works) values ('castile soap', 'Castile Soap', 'Plant-based liquid soap (usually olive- or coconut-derived). The most versatile base in natural cleaners and gentle body products.', '["Health stores","Beauty stores","Continente","Amazon"]'::jsonb, '["Dr. Bronner’s Pure-Castile (unscented)","Sky Organics Castile"]'::jsonb, '["Don’t mix directly with vinegar — they cancel each other out.","Use unscented for baby-safe recipes."]'::jsonb, '[]'::jsonb, '[]'::jsonb, 'Castile soap suspends grease and lifts dirt without harsh surfactants.') on conflict (key) do update set
  title = excluded.title,
  what = excluded.what,
