  best_options = excluded.best_options,
  tips = excluded.tips,
  substitutes = excluded.substitutes,
  allergy_warnings = excluded.allergy_warnings,
  why_it_works = excluded.why_it_works;
insert into public.ingredient_help (key, title, what, where_to_find, best_options, tips, substitutes, allergy_warnings, why_it_works) values ('grated soap', 'Grated Soap', 'A bar of soap shredded into fine flakes so it dissolves into laundry detergents and cleaners.', '["Laundry aisle","Natural stores","Amazon","Or grate any plain bar with a cheese grater"]'::jsonb, '["Castile soap bars","Unscented laundry bars (Fels-Naptha, Sabão Macaco)","Sensitive-skin bars"]'::jsonb, '["Avoid heavily perfumed bars when making baby-safe detergent."]'::jsonb, '[]'::jsonb, '[]'::jsonb, null) on conflict (key) do update set
